<?php
 namespace League\CommonMark\Block\Element; use League\CommonMark\Cursor; class ListItem extends AbstractBlock { protected $listData; public function __construct(ListData $listData) { $this->listData = $listData; } public function getListData(): ListData { return $this->listData; } public function canContain(AbstractBlock $block): bool { return true; } public function isCode(): bool { return false; } public function matchesNextLine(Cursor $cursor): bool { if ($cursor->isBlank()) { if ($this->firstChild === null) { return false; } $cursor->advanceToNextNonSpaceOrTab(); } elseif ($cursor->getIndent() >= $this->listData->markerOffset + $this->listData->padding) { $cursor->advanceBy($this->listData->markerOffset + $this->listData->padding, true); } else { return false; } return true; } public function shouldLastLineBeBlank(Cursor $cursor, int $currentLineNumber): bool { return $cursor->isBlank() && $this->startLine < $currentLineNumber; } } 